require_once __DIR__.'/functions.php';require_login();$staff=current_staff_profile();if(!$staff){http_response_code(400);exit('Tu acceso proviene de .env. Crea una cuenta administrativa MySQL para usar un perfil social.');}
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();try{$name=trim((string)($_POST['display_name']??''));$bio=trim((string)($_POST['bio']??''));$public=isset($_POST['profile_public'])?1:0;if(mb_strlen($name)<2||mb_strlen($name)>100||mb_strlen($bio)>500)throw new RuntimeException('Revisa el nombre y la biografía.');$avatar=upload_avatar($_FILES['avatar']??[]);$pdo=db();$pdo->beginTransaction();$sql='UPDATE users SET display_name=?,bio=?,profile_public=?'.($avatar?',avatar=?':'').' WHERE id=?';$args=[$name,$bio,$public];if($avatar)$args[]=$avatar;$args[]=$staff['id'];$pdo->prepare($sql)->execute($args);$pdo->prepare('UPDATE posts SET author_name=? WHERE author_id=?')->execute([$name,$staff['id']]);$pdo->prepare('UPDATE comments SET nombre=? WHERE staff_author_id=?')->execute([$name,$staff['id']]);$pdo->commit();if($avatar)delete_image($staff['avatar']??null);$_SESSION['display_name']=$name;flash('Perfil del autor actualizado.');redirect('/staff-profile.php');}catch(Throwable $e){if(isset($pdo)&&$pdo->inTransaction())$pdo->rollBack();flash($e->getMessage(),'error');}}
render_header('Mi perfil de autor',['robots'=>'noindex,nofollow']);?><section class="panel narrow"><form method="post" enctype="multipart/form-data"><input type="hidden" name="csrf_token" value="<?=csrf_token()?>"><div class="profile-head"><div class="profile-photo"><div class="avatar-preview" data-avatar-preview><?php if($staff['avatar']):?><img class="avatar avatar-lg" src="/uploads/<?=e($staff['avatar'])?>" alt="Avatar"><?php else:?><span class="avatar avatar-lg avatar-fallback"><?=e(mb_strtoupper(mb_substr($staff['display_name'],0,1)))?></span><?php endif;?></div><label class="avatar-picker"><input type="file" name="avatar" accept="image/png,image/jpeg,image/gif,image/webp" data-avatar-input><span>Elegir imagen</span></label><small data-avatar-status>Máximo 2 MB</small></div><div class="profile-title"><h1>Mi perfil</h1><p class="muted"><?=e(ucfirst($staff['role']))?></p></div></div><label>Nombre público<input name="display_name" maxlength="100" value="<?=e($staff['display_name'])?>" required></label><label>Biografía<textarea name="bio" maxlength="500" rows="4"><?=e($staff['bio'])?></textarea></label><label class="privacy-toggle"><span><strong>Perfil público</strong><small>Permite ver tu perfil, antigüedad y publicaciones.</small></span><input type="checkbox" name="profile_public" value="1" <?=$staff['profile_public']?'checked':''?>><i></i></label><?php if($staff['profile_public']):?><p><a class="text-link" href="<?=e(public_author_url($staff))?>">Ver mi perfil público</a></p><?php endif;?><button class="button">Guardar perfil</button></form></section><script src="/assets/avatar-preview.js?v=<?=e((string)(@filemtime(__DIR__.'/assets/avatar-preview.js')?:'1'))?>" defer></script><?php render_footer();
